import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c,d as o}from"./app-75fed8c6.js";const l={},d=o(`<p>yum（ Yellow dog Updater, Modified）是一个在 Fedora 和 RedHat 以及 SUSE 中的 Shell 前端软件包管理器。</p><p>基于 RPM 包管理，能够从指定的服务器自动下载 RPM 包并且安装，可以自动处理依赖性关系，并且一次安装所有依赖的软件包，无须繁琐地一次次下载、安装。</p><p>yum 提供了查找、安装、删除某一个、一组甚至全部软件包的命令，而且命令简洁而又好记。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>yum <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>command<span class="token punctuation">]</span> <span class="token punctuation">[</span>package <span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>options</code>：可选，选项包括-h（帮助），-y（当安装过程提示选择全部为 &quot;yes&quot;），-q（不显示安装的过程）等等。</li><li><code>command</code>：要进行的操作。</li><li><code>package</code>：安装的包名。</li></ul><h2 id="常用命令" tabindex="-1"><a class="header-anchor" href="#常用命令" aria-hidden="true">#</a> 常用命令</h2><ol><li>列出所有可更新的软件清单命令：<code>yum check-update</code></li><li>更新所有软件命令：<code>yum update</code></li><li>仅安装指定的软件命令：<code>yum install &lt;package_name&gt;</code></li><li>仅更新指定的软件命令：<code>yum update &lt;package_name&gt;</code></li><li>列出所有可安裝的软件清单命令：<code>yum list</code></li><li>删除软件包命令：<code>yum remove &lt;package_name&gt;</code></li><li>查找软件包命令：<code>yum search &lt;keyword&gt;</code></li><li>清除缓存命令: <ul><li><code>yum clean packages</code>: 清除缓存目录下的软件包</li><li><code>yum clean headers</code>: 清除缓存目录下的 headers</li><li><code>yum clean oldheaders</code>: 清除缓存目录下旧的 headers</li><li><code>yum clean</code>, <code>yum clean all</code>:清除缓存目录下的软件包及旧的 headers</li></ul></li></ol>`,8),n=[d];function i(s,t){return a(),c("div",null,n)}const r=e(l,[["render",i],["__file","07.yum.html.vue"]]);export{r as default};
